const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401, error: 'Missing session token' } };
if (!body.email || !body.full_name) return { json: { _empty: true, status: 400, error: 'email and full_name required' } };
return { json: { token: token, email: String(body.email).toLowerCase().trim(), full_name: String(body.full_name).slice(0, 200), phone: body.phone || null, jurisdiction: body.jurisdiction || 'ON' } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && rows.id ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401, error: 'Invalid session' } };
if (row.user_role !== 'mga_principal' && row.user_role !== 'admin') return { json: { _unauthorized: true, status: 403, error: 'mga_principal role required' } };
const i = $('Extract Inputs').item.json;
return { json: { _ok: true, mga_principal_id: row.id || row.user_id, email: i.email, full_name: i.full_name, phone: i.phone, jurisdiction: i.jurisdiction, client_id: row.client_id || null } };

const ctx = $('Check Role').item.json;
const ins = $input.item.json;
const user = Array.isArray(ins) ? ins[0] : ins;
if (!user || !user.id) return { json: { _failed: true, error: 'failed to create or find auth_users row' } };
return { json: { advisor_id: user.id, advisor_email: user.email, mga_principal_id: ctx.mga_principal_id, jurisdiction: ctx.jurisdiction, full_name: user.full_name } };
